// Mocht je data voor morgen willen berekenen, doe dat dan in een aparte flow.
let rawDataVandaag = raw.data.slice(0, 96);

const cheapCount = 4 * 4;        // 16 kwartieren (4 uur laden)
const expensiveMaxCount = 4;  //  max 16 kwartieren (4 uur ontladen)
const minSpread = 0.08;          // 8 cent boven cheap average

function indexToTime(idx) {
    // Zorgt dat index altijd binnen de 0-95 range van 1 dag blijft voor de tijdweergave
    const localIdx = idx % 96; 
    const mins = localIdx * 15;
    const h = Math.floor(mins / 60).toString().padStart(2, '0');
    const m = (mins % 60).toString().padStart(2, '0');
    return `${h}:${m}`;
}

let kwartieren = rawDataVandaag.map((item, index) => ({
    index,
    tijd: indexToTime(index),
    prijs: Number(item.prijsZP)
})).filter(x => !isNaN(x.prijs));

if (kwartieren.length === 0) {
    node.status({ fill: 'red', shape: 'ring', text: 'no valid prices' });
    return null;
}

let goedkoopstePrijs = Math.min(...kwartieren.map(x => x.prijs));

let cheapQuarters = [...kwartieren]
    .sort((a, b) => a.prijs - b.prijs)
    .slice(0, cheapCount)
    .sort((a, b) => a.index - b.index)
    .map(x => x.index);

let cheapPrices = kwartieren
    .filter(x => cheapQuarters.includes(x.index))
    .map(x => x.prijs);

let cheapAvg = cheapPrices.length
    ? cheapPrices.reduce((a, b) => a + b, 0) / cheapPrices.length
    : goedkoopstePrijs;

let duurste = [...kwartieren].sort((a, b) => b.prijs - a.prijs)[0];
let duursteIndex = duurste.index;
let duursteTijd = duurste.tijd;
let duurstePrijs = duurste.prijs;
let spreadDuursteVsCheapAvg = duurstePrijs - cheapAvg;
let spreadDuursteVsGoedkoopste = duurstePrijs - goedkoopstePrijs;
let dischargeAllowed = spreadDuursteVsCheapAvg >= minSpread;

let expensiveQuarters = [...kwartieren]
    .filter(x => x.prijs >= (cheapAvg + minSpread))
    .sort((a, b) => b.prijs - a.prijs)
    .slice(0, expensiveMaxCount)
    .sort((a, b) => a.index - b.index)
    .map(x => x.index);

function mergeQuartersToSlots(quarterIndexes) {
    if (!quarterIndexes.length) return [];

    let slots = [];
    let startIdx = quarterIndexes[0];
    let endIdx = quarterIndexes[0];

    for (let i = 1; i < quarterIndexes.length; i++) {
        if (quarterIndexes[i] === endIdx + 1) {
            endIdx = quarterIndexes[i];
        } else {
            slots.push({
                starttijd: indexToTime(startIdx),
                eindtijd: indexToTime(endIdx + 1)
            });
            startIdx = quarterIndexes[i];
            endIdx = quarterIndexes[i];
        }
    }

    slots.push({
        starttijd: indexToTime(startIdx),
        eindtijd: indexToTime(endIdx + 1)
    });

    return slots;
}

